import{_ as a,o as e,c as s,a2 as n}from"./chunks/framework.DdLJaIXX.js";const c=JSON.parse('{"title":"Investment Memo — CQ","description":"","frontmatter":{},"headers":[],"relativePath":"ir/investment-memo.md","filePath":"ir/investment-memo.md"}'),r={name:"ir/investment-memo.md"};function o(l,t,i,d,h,p){return e(),s("div",null,[...t[0]||(t[0]=[n(`<h1 id="investment-memo-—-cq" tabindex="-1">Investment Memo — CQ <a class="header-anchor" href="#investment-memo-—-cq" aria-label="Permalink to &quot;Investment Memo — CQ&quot;">​</a></h1><p><strong>작성일</strong>: 2026-04-20 <strong>라운드</strong>: Pre-seed <strong>조달 목표</strong>: 5-7억원 <strong>Runway 목표</strong>: 6-9개월 <strong>Ticket size 권장</strong>: 5천만-1.5억원 (Lead 2-3억 + Follow-on Angel/전략적)</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>CQ는 <strong>AI 연구자의 외장 두뇌와 손발</strong>이다. v1.66.0 실물이 이미 돌고 있고, 파일럿 γ가 진행 중이다.</p><p>5-7억원 Pre-seed로 <strong>6-9개월간 &quot;기억이 쌓일수록 떠나기 힘들어진다&quot;라는 핵심 가설을 유료 사용자 100명 수준에서 증명</strong>한다. 이 지표가 확보되면 12개월 내 Seed 라운드(20억원, valuation 100-150억원)로 이어간다.</p><p>본 라운드의 투자자는 <em>아직 증명되지 않은 시장 선점</em>에 베팅하는 것이며, 비교 대상은:</p><ul><li>**W&amp;B (CoreWeave에 $1.7B 인수, 2025-03)**의 초기 Seed 시점 포지션</li><li>**Cursor ($29B valuation, $2B ARR)**의 초기 제품 단계</li></ul><hr><h2 id="_1-why-cq-exists" tabindex="-1">1. Why CQ Exists <a class="header-anchor" href="#_1-why-cq-exists" aria-label="Permalink to &quot;1. Why CQ Exists&quot;">​</a></h2><h3 id="_1-1-고통의-진단" tabindex="-1">1.1 고통의 진단 <a class="header-anchor" href="#_1-1-고통의-진단" aria-label="Permalink to &quot;1.1 고통의 진단&quot;">​</a></h3><p>바이브코딩 시대, 연구자는 자기 아이디어의 대부분을 잃는다. 서버에 붙기 전에 식고, 결과가 나오기 전에 잊히고, 다음 실험에 이어지지 못한다.</p><p>세 개의 증상이 <strong>한 현상의 다른 얼굴</strong>이다.</p><table tabindex="0"><thead><tr><th>증상</th><th>내용</th></tr></thead><tbody><tr><td><strong>기억 단절</strong> (두뇌)</td><td>AI는 매번 초기화된다. 어제의 깨달음이 오늘 프롬프트에 없다.</td></tr><tr><td><strong>실행 마찰</strong> (손)</td><td>ssh·docker·yaml 세팅만 60줄. 아이디어 1개 돌리는 데 10단계.</td></tr><tr><td><strong>서버 유휴</strong> (발)</td><td>비싼 GPU가 밤새 논다. 기업 75%가 활용률 70% 미만 (ClearML 2024).</td></tr></tbody></table><h3 id="_1-2-손실-규모-연구자-1인-×-1년" tabindex="-1">1.2 손실 규모 (연구자 1인 × 1년) <a class="header-anchor" href="#_1-2-손실-규모-연구자-1인-×-1년" aria-label="Permalink to &quot;1.2 손실 규모 (연구자 1인 × 1년)&quot;">​</a></h3><ul><li><strong>3주</strong> — 실험 세팅에 쓰는 시간 (자체 추정, Anaconda State of Data Science 2024 &quot;data prep 45%&quot; 보조 근거)</li><li><strong>$6,000 (≈840만원)</strong> — 유휴 GPU 비용 (ClearML 75% 활용률 &lt; 70% 기반 계산)</li><li><strong>50%</strong> — 자기 실험 재현 실패 (Baker, <em>Nature</em> 533, 2016)</li></ul><p>→ × 수백만 명 = 사라지고 있는 발견들.</p><h3 id="_1-3-현재-대안의-한계" tabindex="-1">1.3 현재 대안의 한계 <a class="header-anchor" href="#_1-3-현재-대안의-한계" aria-label="Permalink to &quot;1.3 현재 대안의 한계&quot;">​</a></h3><p>각각 하나의 축만 해결한다:</p><ul><li><strong>W&amp;B / MLflow / Neptune</strong>: 추적만. 실행·기억 없음. (Neptune은 2025-12 OpenAI 인수로 SaaS 중단)</li><li><strong>SkyPilot / Slurm / RunPod</strong>: 실행만. 기록·연속성 없음.</li><li><strong>ChatGPT / Claude / Cursor</strong>: 대화만. 내 서버·내 데이터 못 씀. 프로바이더 격리.</li><li><strong>Devin / Manus</strong>: 자율 에이전트지만 자기 폐쇄 인프라. 크로스 LLM X.</li></ul><p><strong>세 축을 동시에 해결하는 도구는 지금 존재하지 않는다.</strong></p><hr><h2 id="_2-what-we-ve-built" tabindex="-1">2. What We&#39;ve Built <a class="header-anchor" href="#_2-what-we-ve-built" aria-label="Permalink to &quot;2. What We&#39;ve Built&quot;">​</a></h2><h3 id="_2-1-v1-66-0-2026-04-15-출시-—-실물-증거" tabindex="-1">2.1 v1.66.0 (2026-04-15 출시) — 실물 증거 <a class="header-anchor" href="#_2-1-v1-66-0-2026-04-15-출시-—-실물-증거" aria-label="Permalink to &quot;2.1 v1.66.0 (2026-04-15 출시) — 실물 증거&quot;">​</a></h3><p>단독 창업자가 18개월에 걸쳐 구현:</p><table tabindex="0"><thead><tr><th>기둥</th><th>CQ 구현물</th><th>버전</th></tr></thead><tbody><tr><td>두뇌</td><td><strong>Timeline Graph</strong> — <code>cq_graph_edges</code> + 5 의미 엣지 + Context Injection + Persona</td><td>v1.63.1 / v1.65.0</td></tr><tr><td>손</td><td><strong>Agent Dispatch</strong> — Hub Execution Engine + Worker MCP + Relay + Streamable (3채널)</td><td>v1.60 ~ v1.64</td></tr><tr><td>발</td><td><strong>Research Loop</strong> — LoopOrchestrator + <code>@key=value</code> MetricWriter + Auto-experiment</td><td>v1.55 ~</td></tr><tr><td>뷰</td><td><strong>Evidence Web</strong> — Phase 2 MVP, shadcn + recharts 기반 근거 시각화</td><td>v1.66.0</td></tr></tbody></table><h3 id="_2-2-아키텍처-4층" tabindex="-1">2.2 아키텍처 4층 <a class="header-anchor" href="#_2-2-아키텍처-4층" aria-label="Permalink to &quot;2.2 아키텍처 4층&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[LLM]     Cursor · Claude · ChatGPT · Codex · Gemini</span></span>
<span class="line"><span>  ↕↓      MCP (stdio / Relay / Streamable) — 3채널 배선 완료</span></span>
<span class="line"><span>[CQ]      Timeline + Context Injection + Persona</span></span>
<span class="line"><span>  ↕↓</span></span>
<span class="line"><span>[손발]    Hub Execution Engine + Worker + LoopOrchestrator</span></span>
<span class="line"><span>  ↕↓</span></span>
<span class="line"><span>[내 인프라]  pi (RTX 5080) · DESKTOP (Blackwell ×2) · 4090 · MacBook</span></span></code></pre></div><h3 id="_2-3-실행-증거" tabindex="-1">2.3 실행 증거 <a class="header-anchor" href="#_2-3-실행-증거" aria-label="Permalink to &quot;2.3 실행 증거&quot;">​</a></h3><ul><li>GitLab tag → CI 자동 빌드 → GitHub Releases 자동 푸시 (CD 파이프라인 가동)</li><li>누적 1,000 태스크 중 <strong>913 완료 (91%)</strong></li><li>5대 워커 실시간 연결, 평균 주 2-3회 릴리즈 주기</li><li>Phase 0 → Phase 3 (2026-04-14 단 2일에 Phase 1·2 배선)</li></ul><p><strong>vaporware 아님. 이 지점이 대부분 Pre-seed 창업자와의 결정적 차별이다.</strong></p><hr><h2 id="_3-why-this-is-valuable" tabindex="-1">3. Why This Is Valuable <a class="header-anchor" href="#_3-why-this-is-valuable" aria-label="Permalink to &quot;3. Why This Is Valuable&quot;">​</a></h2><h3 id="_3-1-렌즈-1-—-대화가-지식이-되는-전환" tabindex="-1">3.1 렌즈 1 — 대화가 &quot;지식이 되는&quot; 전환 <a class="header-anchor" href="#_3-1-렌즈-1-—-대화가-지식이-되는-전환" aria-label="Permalink to &quot;3.1 렌즈 1 — 대화가 &quot;지식이 되는&quot; 전환&quot;">​</a></h3><p>기존 AI 도구의 전제: <em>대화는 휘발한다</em>. CQ의 전제: <strong>대화는 지식이 된다</strong>.</p><p>매 세션의 결정·실패·발견이 Timeline Edge로 누적되고, 다음 대화의 입력(Context Injection)이 된다. 이것은 <em>생산성 도구</em>가 아니라 <em>인지 기반의 전환</em>이다. 투자자가 가장 흥분해야 하는 지점.</p><h3 id="_3-2-렌즈-2-—-persona-누적으로-나의-그림자" tabindex="-1">3.2 렌즈 2 — Persona 누적으로 &quot;나의 그림자&quot; <a class="header-anchor" href="#_3-2-렌즈-2-—-persona-누적으로-나의-그림자" aria-label="Permalink to &quot;3.2 렌즈 2 — Persona 누적으로 &quot;나의 그림자&quot;&quot;">​</a></h3><p>6개월 이상 쓰면 사용자의 결정 패턴·용어·우선순위가 누적된다. 이 Persona는 다른 어디에도 옮길 수 없다. <strong>1년 쓴 사용자가 CQ를 떠나는 비용은 &quot;Cursor에서 Copilot으로 옮기는 비용&quot;과 차원이 다르다.</strong></p><h3 id="_3-3-렌즈-3-—-크로스-llm-빅테크가-구조적으로-못-만드는-자리" tabindex="-1">3.3 렌즈 3 — 크로스 LLM, 빅테크가 구조적으로 못 만드는 자리 <a class="header-anchor" href="#_3-3-렌즈-3-—-크로스-llm-빅테크가-구조적으로-못-만드는-자리" aria-label="Permalink to &quot;3.3 렌즈 3 — 크로스 LLM, 빅테크가 구조적으로 못 만드는 자리&quot;">​</a></h3><ul><li>OpenAI는 자기 프로바이더 lock-in이 BM. &quot;모든 LLM을 가로지르는 기억&quot;을 만들면 자사 전략이 무너진다.</li><li>Anthropic·Google도 마찬가지.</li><li><strong>이 공백은 스타트업만 채울 수 있다</strong>.</li></ul><p>MCP 표준화(2024-11)로 이 공백이 기술적으로 접근 가능해졌다. CQ는 stdio/Relay/Streamable 3채널을 이미 배선한 최초 도구.</p><h3 id="_3-4-렌즈-4-—-가치의-비선형-축적" tabindex="-1">3.4 렌즈 4 — 가치의 비선형 축적 <a class="header-anchor" href="#_3-4-렌즈-4-—-가치의-비선형-축적" aria-label="Permalink to &quot;3.4 렌즈 4 — 가치의 비선형 축적&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>가치</span></span>
<span class="line"><span> │                        ╱  평생 자산 (5년)</span></span>
<span class="line"><span> │                      ╱</span></span>
<span class="line"><span> │                    ╱─── Persona 축적 (6-12개월)</span></span>
<span class="line"><span> │                  ╱</span></span>
<span class="line"><span> │                ╱── 대화→지식 전환 (1개월)</span></span>
<span class="line"><span> │              ╱</span></span>
<span class="line"><span> │            ╱</span></span>
<span class="line"><span> │          ╱── 단기 시간 절약 (1주)</span></span>
<span class="line"><span> │        ╱</span></span>
<span class="line"><span> └──────────────────────→ 시간</span></span>
<span class="line"><span>   1주  1달  3달   1년   3년</span></span></code></pre></div><ul><li>1주 사용자: &quot;편하네&quot;</li><li>3달 사용자: &quot;없으면 불편&quot;</li><li>1년 사용자: <strong>&quot;떠날 수 없음&quot;</strong></li></ul><p>이 비선형 곡선이 모든 BM 계산(retention·LTV·CAC)의 뿌리다. AI wrapper 평균 90일 이탈률 65%를 <strong>구조적으로 우회</strong>할 수 있는 유일한 방법.</p><hr><h2 id="_4-why-now-why-us" tabindex="-1">4. Why Now, Why Us <a class="header-anchor" href="#_4-why-now-why-us" aria-label="Permalink to &quot;4. Why Now, Why Us&quot;">​</a></h2><h3 id="_4-1-why-now-—-세-흐름의-수렴-2026" tabindex="-1">4.1 Why Now — 세 흐름의 수렴 (2026) <a class="header-anchor" href="#_4-1-why-now-—-세-흐름의-수렴-2026" aria-label="Permalink to &quot;4.1 Why Now — 세 흐름의 수렴 (2026)&quot;">​</a></h3><ol><li><strong>에이전트 실행 주체화</strong> — Cursor 100만+ 유료 개발자, Claude Code 대중화, Codex 확산. AI가 &quot;대화상대&quot;에서 &quot;실행 주체&quot;로 전환됨.</li><li><strong>MCP 표준화</strong> — Anthropic 2024-11 공개 → Cursor·Claude·ChatGPT가 동일 MCP 서버에 붙음. 크로스 프로바이더 기억·손발이 기술적으로 가능해짐.</li><li><strong>바이브코딩 대중화</strong> — 생물/사회과학/인문학 박사도 에이전트로 연구. 전통 ML 외 연구자로 TAM 4배 확장.</li></ol><blockquote><p><strong>2년 전엔 기술적으로 불가능. 2년 후엔 빅테크가 lock-in 완성.</strong><strong>이 3년이 창이다.</strong></p></blockquote><h3 id="_4-2-why-us" tabindex="-1">4.2 Why Us <a class="header-anchor" href="#_4-2-why-us" aria-label="Permalink to &quot;4.2 Why Us&quot;">​</a></h3><ul><li><strong>실행 속도 증명</strong> — 단독으로 v1.60 → v1.66까지 6개월. 대다수 Seed 덱은 이 정도를 <em>약속</em>만 한다. CQ는 이미 해냈다.</li><li><strong>기술 스택 일관성</strong> — Go(cq 코어) · Python(워커 사이드카) · Supabase(두뇌) · MCP(손발). 한 머릿속에서 설계. 크로스 LLM moat는 분절된 팀으론 못 만든다.</li><li><strong>연구자 현장 이해</strong> — 창업자 본인이 UTH-CT·HMR 등 ML 실험을 직접 수십 회 돌리며 겪은 3고통으로부터 제품화. 도메인 진짜성.</li></ul><hr><h2 id="_5-risks-how-we-address" tabindex="-1">5. Risks &amp; How We Address <a class="header-anchor" href="#_5-risks-how-we-address" aria-label="Permalink to &quot;5. Risks &amp; How We Address&quot;">​</a></h2><h3 id="r1-pmf-아직-증명-전-🔴" tabindex="-1">R1. PMF 아직 증명 전 🔴 <a class="header-anchor" href="#r1-pmf-아직-증명-전-🔴" aria-label="Permalink to &quot;R1. PMF 아직 증명 전 🔴&quot;">​</a></h3><ul><li><strong>현실</strong>: 결제 $0, 파일럿 γ 4주 초반.</li><li><strong>대응</strong>: 6-9개월 Pre-seed runway의 <em>유일한</em> 목표는 <strong>유료 100명 × retention 70% × ARR 1억원</strong>. 이 증거가 Seed 게이트. 달성 못하면 Seed 미루고 재검토.</li></ul><h3 id="r2-1인-팀-🔴" tabindex="-1">R2. 1인 팀 🔴 <a class="header-anchor" href="#r2-1인-팀-🔴" aria-label="Permalink to &quot;R2. 1인 팀 🔴&quot;">​</a></h3><ul><li><strong>현실</strong>: 엔지니어링은 혼자 증명됐지만 영업·마케팅·커뮤니티 공백.</li><li><strong>대응</strong>: Pre-seed 자금의 50%를 <em>공동창업자 + 첫 엔지니어 채용</em>에 투입. 본 라운드 후 3개월 내 2인 체제 이행 목표.</li></ul><h3 id="r3-빅테크-경쟁-궤적-🟡" tabindex="-1">R3. 빅테크 경쟁 궤적 🟡 <a class="header-anchor" href="#r3-빅테크-경쟁-궤적-🟡" aria-label="Permalink to &quot;R3. 빅테크 경쟁 궤적 🟡&quot;">​</a></h3><ul><li><strong>위협</strong>: OpenAI Connectors, Cursor memory 강화, Google 에이전트 등.</li><li><strong>대응 3축</strong>: <ul><li>(a) MCP 표준 활용으로 공격적 크로스 LLM 배선 → 점유 선점</li><li>(b) Open source 일부 공개 (Timeline Edge 스키마, Context Injection 엔진 일부) → 커뮤니티 moat</li><li>(c) Persona·Timeline 1년 누적 switching cost → 시간의 moat</li></ul></li></ul><h3 id="r4-타겟-스펙트럼-🟡" tabindex="-1">R4. 타겟 스펙트럼 🟡 <a class="header-anchor" href="#r4-타겟-스펙트럼-🟡" aria-label="Permalink to &quot;R4. 타겟 스펙트럼 🟡&quot;">​</a></h3><ul><li><strong>위험</strong>: &quot;바이브코딩 시대 연구자&quot;는 박사~기업 ML까지 넓음. 메시지 분산.</li><li><strong>대응</strong>: Pre-seed 기간 중 <strong>첫 1,000명 Early Bird cohort를 박사과정생(특히 바이브코딩 비전공 연구자)으로 좁혀</strong> 서사 단일화. 확장은 Seed 이후.</li></ul><h3 id="r5-가격-전략-리스크-🟢" tabindex="-1">R5. 가격 전략 리스크 🟢 <a class="header-anchor" href="#r5-가격-전략-리스크-🟢" aria-label="Permalink to &quot;R5. 가격 전략 리스크 🟢&quot;">​</a></h3><ul><li><strong>위험</strong>: $36/yr = 5만원은 Cursor($240)의 7배 저렴. ARPU로 $2B SAM 채우려면 Team tier 전환율이 핵심.</li><li><strong>대응</strong>: Team seat $500/yr로 14× 객단가 점프 설계. 회사 knowledge 자산 + GPU 풀링 + 관리자 기능으로 정당화.</li></ul><hr><h2 id="_6-ask-milestones" tabindex="-1">6. Ask &amp; Milestones <a class="header-anchor" href="#_6-ask-milestones" aria-label="Permalink to &quot;6. Ask &amp; Milestones&quot;">​</a></h2><h3 id="_6-1-ask" tabindex="-1">6.1 Ask <a class="header-anchor" href="#_6-1-ask" aria-label="Permalink to &quot;6.1 Ask&quot;">​</a></h3><table tabindex="0"><thead><tr><th>항목</th><th>값</th></tr></thead><tbody><tr><td><strong>금액</strong></td><td>5-7억원 Pre-seed</td></tr><tr><td><strong>지분 희석</strong></td><td>8-12%</td></tr><tr><td><strong>Runway</strong></td><td>6-9개월</td></tr><tr><td><strong>예상 Pre-money Valuation</strong></td><td>40-60억원</td></tr><tr><td><strong>Lead</strong></td><td>1개 VC/Angel (2-3억) + Follow-on 3-5명</td></tr></tbody></table><h3 id="_6-2-사용처" tabindex="-1">6.2 사용처 <a class="header-anchor" href="#_6-2-사용처" aria-label="Permalink to &quot;6.2 사용처&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>엔지니어링         50%    2.5-3.5억     공동창업자 + 엔지니어 1명</span></span>
<span class="line"><span>마케팅·커뮤니티     25%    1.25-1.75억   학회 발표, HN 포스트, OSS 배포, Knowledge Drop</span></span>
<span class="line"><span>인프라              15%    0.75-1.05억   Supabase, Cloudflare, Relay 증설</span></span>
<span class="line"><span>운영                10%    0.5-0.7억     법무·회계·일반관리</span></span></code></pre></div><h3 id="_6-3-milestones-6-9개월" tabindex="-1">6.3 Milestones (6-9개월) <a class="header-anchor" href="#_6-3-milestones-6-9개월" aria-label="Permalink to &quot;6.3 Milestones (6-9개월)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>시점</th><th>목표</th></tr></thead><tbody><tr><td>M3</td><td>파일럿 γ 종료, retention·ARPU·활성일수 지표 확정</td></tr><tr><td>M6</td><td>유료 사용자 100명 돌파, ARR 1천만원, 공동창업자 합류 완료</td></tr><tr><td>M9</td><td>유료 사용자 500명, ARR 5천만원, Seed 지표 충족</td></tr></tbody></table><h3 id="_6-4-seed-시나리오-본-라운드-이후-12개월" tabindex="-1">6.4 Seed 시나리오 (본 라운드 이후 12개월) <a class="header-anchor" href="#_6-4-seed-시나리오-본-라운드-이후-12개월" aria-label="Permalink to &quot;6.4 Seed 시나리오 (본 라운드 이후 12개월)&quot;">​</a></h3><ul><li>유료 사용자 1,000-5,000명</li><li>ARR 1-5억원</li><li>Team seat 첫 10-50개 조직</li><li>Seed 조달: 20억원, valuation 100-150억원</li><li>조달 후 24개월 runway로 ARR 50억원 목표</li></ul><hr><h2 id="부록-a-—-채워야-할-공란-창업자-작성" tabindex="-1">부록 A — 채워야 할 공란 (창업자 작성) <a class="header-anchor" href="#부록-a-—-채워야-할-공란-창업자-작성" aria-label="Permalink to &quot;부록 A — 채워야 할 공란 (창업자 작성)&quot;">​</a></h2><ul><li>[ ] Founder 성명·학력·경력 (특히 ML 실험 현장 경험)</li><li>[ ] 파일럿 γ 4주 실측 지표 (retention, NPS, 활성 일수, 평균 실험 수)</li><li>[ ] 기술 공동창업자 / 첫 엔지니어 후보 명단 (nominal이라도)</li><li>[ ] 초기 투자자 Lead 후보 (VC·Angel·전략적 투자자)</li><li>[ ] Knowledge Drop 첫 콘텐츠 샘플 (콘텐츠-시장 적합성 증거)</li><li>[ ] 자문단(Advisor) 후보 (ML 연구자·MLOps 전문가)</li></ul><h2 id="부록-b-—-faq-투자자-예상-질문" tabindex="-1">부록 B — FAQ (투자자 예상 질문) <a class="header-anchor" href="#부록-b-—-faq-투자자-예상-질문" aria-label="Permalink to &quot;부록 B — FAQ (투자자 예상 질문)&quot;">​</a></h2><ol><li><p><strong>왜 W&amp;B/CoreWeave가 이걸 못 하나?</strong> → W&amp;B는 &quot;추적·로그&quot; 중심. 에이전트 실행 주체화·크로스 LLM 기억 DNA 없음. CoreWeave는 GPU 클라우드 사업자이지 UX 레이어 아님.</p></li><li><p><strong>Cursor가 memory 확장하면?</strong> → Cursor는 IDE 내부. CQ는 IDE 외부 지속성. Cursor memory는 프로젝트 단위·프로바이더 격리. CQ는 크로스 프로바이더.</p></li><li><p><strong>왜 연간 결제만?</strong> → AI wrapper 90일 이탈률 65%를 구조적으로 우회. 12개월 기억 축적이 switching cost의 본체.</p></li><li><p><strong>팀 seat $500/yr의 근거는?</strong> → W&amp;B Enterprise $600+/seat와 유사 구간. 팀 knowledge 공유 + GPU 풀 + 관리자 기능으로 정당화.</p></li><li><p><strong>Open source 전략은?</strong> → Core는 closed, Timeline Edge 스키마·Context Injection 기본 엔진·MCP 클라이언트는 open. Hub/Persona/Research Loop는 closed.</p></li><li><p><strong>왜 한국 창업자/한국 VC?</strong> → 글로벌 제품이지만 MCP 생태계 초기라 팀 크기보다 실행 속도가 결정적. 한국 VC의 Pre-seed 구간($500K-$1M)은 실행 증명 단계에 최적.</p></li></ol><hr><h2 id="부록-c-—-주요-인용-출처" tabindex="-1">부록 C — 주요 인용 출처 <a class="header-anchor" href="#부록-c-—-주요-인용-출처" aria-label="Permalink to &quot;부록 C — 주요 인용 출처&quot;">​</a></h2><table tabindex="0"><thead><tr><th>주장</th><th>출처</th></tr></thead><tbody><tr><td>GPU 활용률 &lt; 70% (기업 75%)</td><td>ClearML, <em>The State of AI Infrastructure at Scale</em> (2024)</td></tr><tr><td>재현 실패 50%/70%</td><td>Baker, M. &quot;1,500 scientists lift the lid on reproducibility&quot;, <em>Nature</em> 533, 452-454 (2016)</td></tr><tr><td>MLOps 시장 $2-4B → $16-20B</td><td>Fortune Business Insights, Grand View Research, GM Insights (2024-2025)</td></tr><tr><td>W&amp;B → CoreWeave $1.7B 인수</td><td>CoreWeave Press Release, 2025-03-04 / TechCrunch</td></tr><tr><td>Cursor 100만 유료·$2B ARR</td><td>Sacra, Contrary Research (2026-02)</td></tr><tr><td>AI/ML 엔지니어 50만+</td><td>World Economic Forum, Future of Jobs 2025</td></tr><tr><td>data prep 45%</td><td>Anaconda, <em>State of Data Science 2024</em></td></tr></tbody></table><hr><p><em>본 문서는 지속 업데이트됨. 최종 확정판은 파일럿 γ 실측 지표 확보 후 작성.</em></p>`,84)])])}const g=a(r,[["render",o]]);export{c as __pageData,g as default};
